import json
import base64

payloads = {
    "hashtree_bridge.py": "",
    "substrate.toml": ""
}

def canonize():
    report = {
        "substrate_id": "1101",
        "name": "Hashtree Bridge",
        "status": "CANONIZED_FULL",
        "Files": {
            "hashtree_bridge.py": base64.b64decode(payloads["hashtree_bridge.py"]).decode("utf-8"),
            "substrate.toml": base64.b64decode(payloads["substrate.toml"]).decode("utf-8"),
        }
    }
    return json.dumps(report, indent=2)

if __name__ == "__main__":
    print(canonize())
